# Human evaluation results computation
# Processes Google Form responses for the native speaker evaluation described
# in thesis Chapter 6, Section 6.6.
# Input files needed (not included in repo):
# {lang}_human_eval_mapping.csv : generated by rationale_extraction.py
# {lang}_form_responses.csv : raw Google Form export from Google Sheets
# The mapping file links each evaluation item to its stratum and setup assignment.
# The form responses file contains one row per evaluator with their ratings.
# Column structure: [0] timestamp, [1] gender, [2] age range, followed by stratum 1 rating pairs and stratum 2 yes/no answers
# Requirements: pip install pandas numpy
# Set BASE_DIR to the folder containing your input CSVs before running.

import os
import numpy as np
import pandas as pd

BASE_DIR   = './human_evaluation'
OUTPUT_DIR = './output'
os.makedirs(OUTPUT_DIR, exist_ok=True)

# language configurations
# gender_map: maps raw form strings to male/female
# valid_answer: the yes/validated answer string in stratum 2
# s2_count: number of stratum 2 items
LANG_CONFIG = {
    'farsi': {
        'mapping_file':  'farsi_human_eval_mapping.csv',
        'forms_file':    'farsi_form_responses.csv',
        'gender_map':    {'مرد': 'male', 'زن': 'female'},
        'valid_answer':  'آره، ایراد وارد شده درسته و مستند به متنه',
        's2_count':      11,
    },
    'italian': {
        'mapping_file':  'italian_human_eval_mapping.csv',
        'forms_file':    'italian_form_responses.csv',
        'gender_map':    {'Uomo': 'male', 'Donna': 'female'},
        'valid_answer':  None,   # auto-detected from most common answer
        's2_count':      6,
    }
}


def build_tidy_s1(mapping, forms, s1):
    """
    Builds a long-form dataframe from stratum 1 ratings.
    Each row is one evaluator rating one item under one setup (B1 or M1).
    Rating columns in the form are paired: columns 3-4 for item 1, 5-6 for item 2, etc.
    """
    s1_col_pairs = [(3 + i * 2, 4 + i * 2) for i in range(10)]
    records = []

    for i, row in s1.iterrows():
        col_a_idx, col_b_idx = s1_col_pairs[i]
        col_a = forms.columns[col_a_idx]
        col_b = forms.columns[col_b_idx]
        for _, ev in forms.iterrows():
            score_a = pd.to_numeric(ev[col_a], errors='coerce')
            score_b = pd.to_numeric(ev[col_b], errors='coerce')
            records.append({
                'text_id':             row['text_id'],
                'evaluator':           ev[forms.columns[0]],
                'gender':              ev['gender'],
                row['option_a_setup']: score_a,
                row['option_b_setup']: score_b,
            })

    tidy = []
    for rec in records:
        for setup in ['B1', 'M1']:
            if setup in rec:
                tidy.append({
                    'text_id':   rec['text_id'],
                    'evaluator': rec['evaluator'],
                    'gender':    rec['gender'],
                    'setup':     setup,
                    'score':     rec[setup]
                })

    return pd.DataFrame(tidy).dropna(subset=['score'])


def build_s2_records(forms, s2, s2_cols, valid_answer):
    """
    Builds stratum 2 validation records.
    Each row is one evaluator's yes/no validation of one asymmetric detection item.
    """
    records = []
    for i, row in s2.iterrows():
        col = s2_cols[i]
        setup = row['option_a_setup']
        for _, ev in forms.iterrows():
            answer = ev[col]
            records.append({
                'text_id': row['text_id'],
                'setup':   setup,
                'gender':  ev['gender'],
                'valid':   1 if str(answer).strip() == valid_answer else 0,
                'answer':  answer
            })
    return pd.DataFrame(records)


def run_human_eval(lang_name, config):
    print(f"\n{'='*60}")
    print(f"human evaluation results: {lang_name.upper()}")
    print(f"{'='*60}")

    mapping = pd.read_csv(os.path.join(BASE_DIR, config['mapping_file']))
    forms   = pd.read_csv(os.path.join(BASE_DIR, config['forms_file']))

    # map gender strings to male/female
    gender_col = forms.columns[1]
    forms['gender'] = forms[gender_col].map(config['gender_map'])

    s1 = mapping[mapping['stratum'] == 1].reset_index(drop=True)
    s2 = mapping[mapping['stratum'] == 2].reset_index(drop=True)

    print(f"evaluators: {len(forms)} | stratum 1 items: {len(s1)} | stratum 2 items: {len(s2)}")
    print(f"gender distribution: {forms['gender'].value_counts().to_dict()}")

    # stratum 1: paired a/b ratings
    df = build_tidy_s1(mapping, forms, s1)

    sep = "-" * 60

    print(f"\n{sep}")
    print("stratum 1 — overall mean scores (1-4 scale)")
    print(sep)
    overall = df.groupby('setup')['score'].agg(['mean', 'std', 'count'])
    print(overall.round(3))

    print(f"\n{sep}")
    print("stratum 1 — mean scores by gender")
    print(sep)
    by_gender = df.groupby(['setup', 'gender'])['score'].mean().unstack()
    print(by_gender.round(3))

    print(f"\n{sep}")
    print("stratum 1 — gender disparity (delta = |male - female|)")
    print(sep)
    for setup in ['B1', 'M1']:
        sub = df[df['setup'] == setup]
        male_mean   = sub[sub['gender'] == 'male']['score'].mean()
        female_mean = sub[sub['gender'] == 'female']['score'].mean()
        delta = abs(male_mean - female_mean)
        print(f"  {setup}: male={male_mean:.3f}, female={female_mean:.3f}, delta={delta:.3f}")

    print(f"\n{sep}")
    print("stratum 1 — per-item mean scores")
    print(sep)
    per_item = df.groupby(['text_id', 'setup'])['score'].mean().unstack().round(3)
    per_item['B1_minus_M1'] = (per_item['B1'] - per_item['M1']).round(3)
    print(per_item.to_string())

    # stratum 2: asymmetric detection validation
    s2_cols = [forms.columns[23 + i] for i in range(config['s2_count'])]

    # auto-detect valid answer if not specified
    valid_answer = config['valid_answer']
    if valid_answer is None:
        all_answers = []
        for col in s2_cols:
            all_answers.extend(forms[col].dropna().tolist())
        valid_answer = pd.Series(all_answers).value_counts().index[0]
        print(f"\nauto-detected valid answer string: '{valid_answer}'")
        print("verify this is the yes/validated answer before trusting results below")

    s2df = build_s2_records(forms, s2, s2_cols, valid_answer)

    print(f"\n{sep}")
    print("stratum 2 — validation rate per setup")
    print(sep)
    for setup in ['B1', 'M1']:
        sub = s2df[s2df['setup'] == setup]
        total     = len(sub)
        validated = sub['valid'].sum()
        rate      = validated / total if total > 0 else 0
        print(f"  {setup}: appeared {total} times | validated {int(validated)} | "
              f"rate {rate:.1%}")

    print(f"\n{sep}")
    print("stratum 2 — per item breakdown")
    print(sep)
    s2_item = s2df.groupby(['text_id', 'setup'])['valid'].agg(['sum', 'count'])
    s2_item['rate'] = (s2_item['sum'] / s2_item['count']).round(3)
    print(s2_item.to_string())


if __name__ == '__main__':
    for lang_name, config in LANG_CONFIG.items():
        run_human_eval(lang_name, config)
    print("\ndone.")
